# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os

def lambda_handler(event, context):
    # Database connection parameters
    rds_host = os.environ['RDS_HOST']
    name = os.environ['RDS_USERNAME']
    password = os.environ['RDS_PASSWORD']
    db_name = os.environ['RDS_DATABASE']
    
    # Establish database connection
    connection = pymysql.connect(host=rds_host, user=name, password=password, database=db_name)
    
    # Get search parameters from API Gateway event
    search_params = event.get('queryStringParameters', {})
    search_conditions = []
    query_params = []
    
    # Build SQL query dynamically
    if 'name' in search_params:
        search_conditions.append("product_name LIKE %s")
        query_params.append('%' + search_params['name'] + '%')
    if 'category' in search_params:
        search_conditions.append("category = %s")
        query_params.append(search_params['category'])
    if 'price_min' in search_params:
        search_conditions.append("price >= %s")
        query_params.append(search_params['price_min'])
    if 'price_max' in search_params:
        search_conditions.append("price <= %s")
        query_params.append(search_params['price_max'])
    
    where_clause = " AND ".join(search_conditions)
    
    sql_query = "SELECT * FROM products"
    if where_clause:
        sql_query += " WHERE " + where_clause
    
    # Execute SQL query
    with connection.cursor() as cursor:
        cursor.execute(sql_query, query_params)
        results = cursor.fetchall()
    
    # Close connection
    connection.close()
    
    # Return response
    return {
        'statusCode': 200,
        'body': json.dumps(results)
    }